Here are the authoritative public test cases for feature9_2_reserved_helper:
{
  "description": "Custom helper names must not collide with the built-in endpoint surface. Declaring a helper whose name is already reserved (such as the reset or sync controls) fails fast at construction time with a neutral error that names the offending helper and the endpoint, rather than leaking any host runtime exception identity.",
  "cases": [
    {
      "input": {
        "op": "reserved_helper",
        "endpoints": {
          "test": {
            "url": "/test/:id",
            "helpersReserved": [
              "reset"
            ]
          }
        },
        "fetch": "echo_url"
      },
      "expected_output": "error=helper_name_reserved helper=reset endpoint=test\n"
    },
    {
      "input": {
        "op": "reserved_helper",
        "endpoints": {
          "test": {
            "url": "/test/:id",
            "helpersReserved": [
              "sync"
            ]
          }
        },
        "fetch": "echo_url"
      },
      "expected_output": "error=helper_name_reserved helper=sync endpoint=test\n"
    }
  ]
}

Here are the authoritative public test cases for feature9_1_async_chain:
{
  "description": "An async helper runs a sequence of endpoint actions one after another, waiting for each to finish before starting the next, and resolves with the data of the final step. After the chain completes, each endpoint's slice holds its own fetched data. This case chains two endpoints and reports the final result plus both stored slices.",
  "cases": [
    {
      "input": {
        "op": "async_chain",
        "endpoints": {
          "test": "/api/url",
          "test2": "/api/url2"
        },
        "fetch": "echo_url",
        "sequence": [
          "test",
          "test2"
        ]
      },
      "expected_output": "result={\"data\":\"/api/url2\"}\nstate test={\"data\":\"/api/url\"}\nstate test2={\"data\":\"/api/url2\"}\n"
    }
  ]
}

Here are the authoritative public test cases for feature8_4_prefetch_dependency:
{
  "description": "An endpoint can declare prefetch dependencies that must run before its own request. This case configures one endpoint whose prefetch step dispatches another endpoint first; the reported routed URLs show the dependency is fetched before the dependent endpoint.",
  "cases": [
    {
      "input": {
        "op": "call_endpoint",
        "endpoints": {
          "test": "/test",
          "test1": {
            "url": "/test1",
            "prefetchOf": "test"
          }
        },
        "fetch": "echo_url",
        "calls": [
          {
            "endpoint": "test1"
          }
        ]
      },
      "expected_output": "action type=@@redux-api@test1 syncing=false request={\"params\":null,\"pathvars\":null}\naction type=@@redux-api@test syncing=false request={\"params\":{},\"pathvars\":null}\naction type=@@redux-api@test_success syncing=false request={\"params\":{},\"pathvars\":null} data={\"data\":\"/test\"}\naction type=@@redux-api@test1_success syncing=false request={\"params\":null,\"pathvars\":null} data={\"data\":\"/test1\"}\nstate test={\"data\":{\"data\":\"/test\"},\"error\":null,\"loading\":false,\"sync\":true,\"syncing\":false}\nstate test1={\"data\":{\"data\":\"/test1\"},\"error\":null,\"loading\":false,\"sync\":true,\"syncing\":false}\n"
    }
  ]
}

Here are the authoritative public test cases for feature8_3_response_handler:
{
  "description": "A global response handler is invoked for every pure request outcome. On success it receives a null error and the response data; on failure it receives the error (normalized to a neutral category) and no data. This case reports the handler observations for a successful and a failing request.",
  "cases": [
    {
      "input": {
        "op": "pure_request",
        "endpoints": {
          "test": "/test/"
        },
        "fetch": {
          "fixed": {
            "msg": "hello"
          }
        },
        "use": {
          "responseHandler": "record"
        },
        "endpoint": "test"
      },
      "expected_output": "data={\"msg\":\"hello\"}\nfetch_count=1\nresponse data={\"msg\":\"hello\"}\n"
    },
    {
      "input": {
        "op": "pure_request",
        "endpoints": {
          "test": "/test/"
        },
        "fetch": {
          "fail": "boom"
        },
        "use": {
          "responseHandler": "record"
        },
        "endpoint": "test"
      },
      "expected_output": "error=request_failed reason=boom\nresponse error=request_failed reason=boom\n"
    }
  ]
}

