            ]
          }
        },
        "fetch": {
          "fixed": {
            "msg": "hello"
          }
        },
        "calls": [
          {
            "endpoint": "test"
          }
        ]
      },
      "expected_output": "action type=@@redux-api@test syncing=false request={\"params\":null,\"pathvars\":null}\naction type=@@redux-api@test_success syncing=false request={\"params\":null,\"pathvars\":null} data={\"msg\":\"hello\"}\naction type=BROADCAST_ACTION request={\"params\":null,\"pathvars\":null} data={\"msg\":\"hello\"}\nstate test={\"data\":{\"msg\":\"hello\"},\"error\":null,\"loading\":false,\"sync\":true,\"syncing\":false}\n"
