        "op": "call_endpoint",
        "endpoints": {
          "test": {
            "url": "/test/:id",
            "validation": "reject"
          }
        },
        "fetch": {
          "fixed": {
            "msg": "hello"
          }
        },
        "calls": [
          {
            "endpoint": "test",
            "pathvars": {
              "id": 1
            }
          }
