      "expected_output": "action type=@@redux-api@test syncing=false request={\"params\":null,\"pathvars\":{\"id\":1}}\naction type=@@redux-api@test_fail syncing=false request={\"params\":null,\"pathvars\":{\"id\":1}} error=rejected reason=invalid\nstate test={\"data\":{},\"error\":\"invalid\",\"loading\":false,\"sync\":false,\"syncing\":false}\n"
