Here are the authoritative public test cases for feature6_1_crud_helpers:
{
  "description": "Enabling CRUD helpers on an endpoint adds verb shortcuts (get/post/put/delete/patch). Each shortcut forwards its path variables and body params to the transport while forcing the HTTP method, and the routed request descriptor records the method (and body when supplied). This case exercises all five verbs and reports the fetch lifecycle actions, including the method recorded on each request.",
  "cases": [
    {
      "input": {
        "op": "call_endpoint",
        "endpoints": {
          "test": {
            "url": "/test/:id",
            "crud": true
          }
        },
        "fetch": "echo_url_opts",
        "calls": [
          {
            "endpoint": "test",
            "helper": "get",
            "pathvars": {
              "id": 1
            }
          },
          {
            "endpoint": "test",
            "helper": "post",
            "pathvars": {
              "id": 2
            },
            "params": {
              "body": "Hello"
            }
          },
          {
            "endpoint": "test",
            "helper": "put",
            "pathvars": {
              "id": 3
            },
            "params": {
              "body": "World"
            }
          },
          {
            "endpoint": "test",
            "helper": "delete",
            "pathvars": {
              "id": 4
            }
          },
          {
            "endpoint": "test",
            "helper": "patch",
            "pathvars": {
              "id": 5
            },
            "params": {
              "body": "World"
            }
          }
        ]
      },
      "expected_output": "action type=@@redux-api@test syncing=false request={\"params\":{\"method\":\"GET\"},\"pathvars\":{\"id\":1}}\naction type=@@redux-api@test_success syncing=false request={\"params\":{\"method\":\"GET\"},\"pathvars\":{\"id\":1}} data={\"opts\":{\"method\":\"GET\"},\"url\":\"/test/1\"}\naction type=@@redux-api@test syncing=false request={\"params\":{\"body\":\"Hello\",\"method\":\"POST\"},\"pathvars\":{\"id\":2}}\naction type=@@redux-api@test_success syncing=false request={\"params\":{\"body\":\"Hello\",\"method\":\"POST\"},\"pathvars\":{\"id\":2}} data={\"opts\":{\"body\":\"Hello\",\"method\":\"POST\"},\"url\":\"/test/2\"}\naction type=@@redux-api@test syncing=false request={\"params\":{\"body\":\"World\",\"method\":\"PUT\"},\"pathvars\":{\"id\":3}}\naction type=@@redux-api@test_success syncing=false request={\"params\":{\"body\":\"World\",\"method\":\"PUT\"},\"pathvars\":{\"id\":3}} data={\"opts\":{\"body\":\"World\",\"method\":\"PUT\"},\"url\":\"/test/3\"}\naction type=@@redux-api@test syncing=false request={\"params\":{\"method\":\"DELETE\"},\"pathvars\":{\"id\":4}}\naction type=@@redux-api@test_success syncing=false request={\"params\":{\"method\":\"DELETE\"},\"pathvars\":{\"id\":4}} data={\"opts\":{\"method\":\"DELETE\"},\"url\":\"/test/4\"}\naction type=@@redux-api@test syncing=false request={\"params\":{\"body\":\"World\",\"method\":\"PATCH\"},\"pathvars\":{\"id\":5}}\naction type=@@redux-api@test_success syncing=false request={\"params\":{\"body\":\"World\",\"method\":\"PATCH\"},\"pathvars\":{\"id\":5}} data={\"opts\":{\"body\":\"World\",\"method\":\"PATCH\"},\"url\":\"/test/5\"}\nstate test={\"data\":{\"opts\":{\"body\":\"World\",\"method\":\"PATCH\"},\"url\":\"/test/5\"},\"error\":null,\"loading\":false,\"sync\":true,\"syncing\":false}\n"
    }
  ]
}

