    {
      "input": {
        "op": "route_urls",
        "endpoints": {
          "test1": "/url1/",
          "test2": "url2",
          "test3": "",
          "test4": "/(:id)"
        },
        "fetch": {
          "fixed": {
            "msg": "hello"
          }
        },
        "use": {
          "rootUrl": "http://api.ru/"
        },
        "calls": [
          {
            "endpoint": "test1"
