          "b",
          "c"
        ]
      },
      "expected_output": "result=2\n"
    },
    {
      "input": {
        "op": "read_path",
        "object": {
          "a": {
            "b": {
              "c": {
                "0": 2
              }
            }
          }
        },
        "path": [
          "",
          "a",
          null,
          "b",
          null,
          "c",
          0
        ]
      },
      "expected_output": "result=2\n"
